import { Hono } from "hono"
import { cors } from "hono/cors"
import { streamSSE } from "hono/streaming"
import { createMCPServer } from "./server.js"
import { validateNeonAuthToken, type AuthContext } from "./auth/neon-auth.js"

const app = new Hono()

// Enable CORS for Claude Code clients
app.use("*", cors({
  origin: "*",
  allowHeaders: ["Authorization", "Content-Type"],
  allowMethods: ["GET", "POST", "OPTIONS"]
}))

// Health check endpoint
app.get("/health", (c) => {
  return c.json({
    status: "healthy",
    version: "2.0.0",
    transport: "http-sse"
  })
})

// MCP endpoint with SSE transport
app.post("/mcp", async (c) => {
  // 1. Validate Neon Auth token from Authorization header
  const authHeader = c.req.header("Authorization")
  if (!authHeader?.startsWith("Bearer ")) {
    return c.json({ error: "Missing or invalid Authorization header" }, 401)
  }

  const token = authHeader.slice(7)
  const authContext = await validateNeonAuthToken(token)

  if (!authContext) {
    return c.json({ error: "Invalid or expired token" }, 401)
  }

  // 2. Parse MCP request
  const body = await c.req.json()

  // 3. Create org-scoped MCP server and handle request
  const mcpServer = createMCPServer(authContext)
  const response = await mcpServer.handleRequest(body)

  return c.json(response)
})

// SSE endpoint for streaming responses
app.get("/mcp/sse", async (c) => {
  const authHeader = c.req.header("Authorization")
  if (!authHeader?.startsWith("Bearer ")) {
    return c.json({ error: "Unauthorized" }, 401)
  }

  const token = authHeader.slice(7)
  const authContext = await validateNeonAuthToken(token)

  if (!authContext) {
    return c.json({ error: "Invalid token" }, 401)
  }

  return streamSSE(c, async (stream) => {
    const mcpServer = createMCPServer(authContext)

    // Keep connection alive and handle MCP messages
    await mcpServer.handleSSEConnection(stream)
  })
})

// For local development
const port = process.env.PORT || 3001
console.log(`MCP Server running on port ${port}`)

export default app

import * as jose from "jose"
import { getSql } from "../db/connection.js"

export interface AuthContext {
  userId: number
  email: string
  organizationId: number
  organizationSlug: string
  orgRole: "owner" | "admin" | "viewer"
  userRole: "admin" | "viewer"  // System-wide role
}

// Neon Auth JWKS endpoint (get from Neon dashboard)
const NEON_AUTH_JWKS_URL = process.env.NEON_AUTH_JWKS_URL || "https://auth.neon.tech/.well-known/jwks.json"

let jwks: jose.JWTVerifyGetKey | null = null

async function getJWKS(): Promise<jose.JWTVerifyGetKey> {
  if (!jwks) {
    jwks = jose.createRemoteJWKSet(new URL(NEON_AUTH_JWKS_URL))
  }
  return jwks
}

/**
 * Validate Neon Auth token and return user/org context
 */
export async function validateNeonAuthToken(token: string): Promise<AuthContext | null> {
  try {
    // 1. Verify JWT signature with Neon's JWKS
    const jwks = await getJWKS()
    const { payload } = await jose.jwtVerify(token, jwks, {
      // Add any additional verification options
      // issuer: "https://auth.neon.tech"
    })

    // 2. Extract email from token
    const email = payload.email as string
    if (!email) {
      console.error("Token missing email claim")
      return null
    }

    // 3. Look up user and org membership in our database
    const sql = getSql()

    const [userInfo] = await sql`
      SELECT
        u.id as user_id,
        u.email,
        u.role as user_role,
        u.default_org_id,
        o.id as organization_id,
        o.slug as organization_slug,
        om.role as org_role
      FROM dashboard_users u
      LEFT JOIN organizations o ON o.id = u.default_org_id
      LEFT JOIN organization_members om ON om.user_id = u.id AND om.organization_id = o.id
      WHERE u.email = ${email}
    `

    if (!userInfo) {
      console.error(`User not found for email: ${email}`)
      return null
    }

    if (!userInfo.organization_id) {
      console.error(`User ${email} has no organization assigned`)
      return null
    }

    return {
      userId: userInfo.user_id,
      email: userInfo.email,
      organizationId: userInfo.organization_id,
      organizationSlug: userInfo.organization_slug,
      orgRole: userInfo.org_role || "viewer",
      userRole: userInfo.user_role
    }
  } catch (error) {
    console.error("Token validation failed:", error)
    return null
  }
}

/**
 * Validate token and require org admin access
 */
export async function requireOrgAdmin(token: string): Promise<AuthContext | null> {
  const context = await validateNeonAuthToken(token)
  if (!context) return null

  if (context.orgRole !== "owner" && context.orgRole !== "admin") {
    return null
  }

  return context
}

import { Context, Next } from "hono"
import { validateNeonAuthToken, type AuthContext } from "./neon-auth.js"

// Extend Hono context type
declare module "hono" {
  interface ContextVariableMap {
    authContext: AuthContext
  }
}

/**
 * Middleware to validate auth and inject context
 */
export async function authMiddleware(c: Context, next: Next) {
  const authHeader = c.req.header("Authorization")

  if (!authHeader?.startsWith("Bearer ")) {
    return c.json({
      error: "Authorization required",
      message: "Include 'Authorization: Bearer <token>' header"
    }, 401)
  }

  const token = authHeader.slice(7)
  const authContext = await validateNeonAuthToken(token)

  if (!authContext) {
    return c.json({
      error: "Invalid or expired token",
      message: "Please re-authenticate via the dashboard"
    }, 401)
  }

  // Inject auth context for handlers
  c.set("authContext", authContext)

  await next()
}

import { neon, NeonQueryFunction } from "@neondatabase/serverless"

let sql: NeonQueryFunction<false, false> | null = null

export function getSql(): NeonQueryFunction<false, false> {
  if (!sql) {
    const connectionString = process.env.DATABASE_URL
    if (!connectionString) {
      throw new Error("DATABASE_URL environment variable required")
    }
    sql = neon(connectionString)
  }
  return sql
}

import { getSql } from "./connection.js"

// All query functions take organizationId as first parameter
// This ensures data isolation at the query level

export async function getExecutions(
  organizationId: number,
  limit = 50,
  status?: string,
  branch?: string,
  suite?: string,
  from?: string,
  to?: string
) {
  const sql = getSql()

  // Build dynamic WHERE with org filter ALWAYS present
  const conditions = [`organization_id = ${organizationId}`]

  if (status) conditions.push(`status = '${status}'`)
  if (branch) conditions.push(`branch = '${branch}'`)
  if (suite) conditions.push(`suite = '${suite}'`)
  if (from) conditions.push(`started_at >= '${from}'`)
  if (to) conditions.push(`started_at <= '${to}'`)

  return sql.unsafe(`
    SELECT
      id, run_id, branch, commit_sha, commit_message,
      workflow_name, suite, status,
      total_tests, passed, failed, skipped,
      duration_ms, started_at, completed_at
    FROM test_executions
    WHERE ${conditions.join(" AND ")}
    ORDER BY started_at DESC
    LIMIT ${limit}
  `)
}

export async function getExecutionById(
  organizationId: number,
  executionId: number
) {
  const sql = getSql()

  // Org filter ensures user can't access other org's data
  const [execution] = await sql`
    SELECT * FROM test_executions
    WHERE id = ${executionId}
      AND organization_id = ${organizationId}
  `

  return execution || null
}

export async function getTestResultsByExecutionId(
  organizationId: number,
  executionId: number
) {
  const sql = getSql()

  // Join through execution to verify org ownership
  return sql`
    SELECT
      tr.*,
      COALESCE(
        json_agg(
          json_build_object(
            'id', ta.id,
            'type', ta.type,
            'r2_key', ta.r2_key,
            'file_size_bytes', ta.file_size_bytes
          )
        ) FILTER (WHERE ta.id IS NOT NULL),
        '[]'
      ) as artifacts
    FROM test_results tr
    JOIN test_executions te ON te.id = tr.execution_id
    LEFT JOIN test_artifacts ta ON ta.test_result_id = tr.id
    WHERE tr.execution_id = ${executionId}
      AND te.organization_id = ${organizationId}
    GROUP BY tr.id
    ORDER BY tr.started_at
  `
}

export async function searchTests(
  organizationId: number,
  query: string,
  limit = 20
) {
  const sql = getSql()
  const pattern = `%${query}%`

  return sql`
    SELECT
      tr.test_signature,
      tr.test_name,
      tr.test_file,
      COUNT(*) as run_count,
      MAX(tr.started_at) as last_run,
      ROUND(100.0 * COUNT(*) FILTER (WHERE tr.status = 'passed') / COUNT(*), 1) as pass_rate
    FROM test_results tr
    JOIN test_executions te ON te.id = tr.execution_id
    WHERE te.organization_id = ${organizationId}
      AND (tr.test_name ILIKE ${pattern} OR tr.test_file ILIKE ${pattern})
    GROUP BY tr.test_signature, tr.test_name, tr.test_file
    ORDER BY run_count DESC
    LIMIT ${limit}
  `
}

export async function getFailedTests(
  organizationId: number,
  executionId?: number,
  errorType?: string,
  limit = 20
) {
  const sql = getSql()

  const conditions = [
    `te.organization_id = ${organizationId}`,
    `tr.status = 'failed'`
  ]

  if (executionId) {
    conditions.push(`tr.execution_id = ${executionId}`)
  }
  if (errorType) {
    conditions.push(`tr.ai_context->'error'->>'type' ILIKE '%${errorType}%'`)
  }

  return sql.unsafe(`
    SELECT
      tr.id,
      tr.test_name,
      tr.test_file,
      tr.error_message,
      tr.stack_trace,
      tr.is_critical,
      tr.ai_context,
      te.branch,
      te.commit_sha,
      te.run_id
    FROM test_results tr
    JOIN test_executions te ON te.id = tr.execution_id
    WHERE ${conditions.join(" AND ")}
    ORDER BY tr.started_at DESC
    LIMIT ${limit}
  `)
}

export async function getDashboardMetrics(
  organizationId: number,
  from?: string,
  to?: string
) {
  const sql = getSql()

  const conditions = [`organization_id = ${organizationId}`]
  if (from) conditions.push(`started_at >= '${from}'`)
  if (to) conditions.push(`started_at <= '${to}'`)

  const [metrics] = await sql.unsafe(`
    SELECT
      COUNT(*) as total_executions,
      COUNT(*) FILTER (WHERE status = 'success') as successful_runs,
      COUNT(*) FILTER (WHERE status = 'failure') as failed_runs,
      SUM(total_tests) as total_tests_run,
      SUM(passed) as total_passed,
      SUM(failed) as total_failed,
      ROUND(AVG(duration_ms)) as avg_duration_ms
    FROM test_executions
    WHERE ${conditions.join(" AND ")}
  `)

  return metrics
}

export async function getFlakiestTests(
  organizationId: number,
  limit = 10,
  minRuns = 5
) {
  const sql = getSql()

  return sql`
    SELECT *
    FROM test_flakiness_history
    WHERE organization_id = ${organizationId}
      AND total_runs >= ${minRuns}
      AND flaky_runs > 0
    ORDER BY flakiness_rate DESC
    LIMIT ${limit}
  `
}

// ... Additional query functions follow same pattern

import { Server } from "@modelcontextprotocol/sdk/server/index.js"
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
  ListResourcesRequestSchema,
  ReadResourceRequestSchema
} from "@modelcontextprotocol/sdk/types.js"
import { type AuthContext } from "./auth/neon-auth.js"
import { handleToolCall, allTools } from "./tools/index.js"
import { resources, readResource } from "./resources/index.js"

/**
 * Create an MCP server bound to a specific user's auth context.
 * All tool calls automatically filter by the user's organization.
 */
export function createMCPServer(authContext: AuthContext) {
  const server = new Server(
    {
      name: "e2e-dashboard",
      version: "2.0.0"
    },
    {
      capabilities: {
        tools: {},
        resources: {}
      }
    }
  )

  // List available tools
  server.setRequestHandler(ListToolsRequestSchema, async () => {
    return { tools: allTools }
  })

  // Handle tool calls with auth context
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params

    // Pass auth context to tool handler - org filtering happens there
    return handleToolCall(name, args || {}, authContext)
  })

  // List resources
  server.setRequestHandler(ListResourcesRequestSchema, async () => {
    return { resources }
  })

  // Read resources with org context
  server.setRequestHandler(ReadResourceRequestSchema, async (request) => {
    return readResource(request.params.uri, authContext)
  })

  return {
    handleRequest: async (body: any) => {
      // Handle JSON-RPC style request
      return server.handleRequest(body)
    },
    handleSSEConnection: async (stream: any) => {
      // Handle SSE streaming connection
      // Implementation depends on MCP SDK streaming support
    }
  }
}

import { type AuthContext } from "../auth/neon-auth.js"
import * as queries from "../db/queries.js"
import { z } from "zod"

// Tool definitions for MCP
export const allTools = [
  {
    name: "get_executions",
    description: "List test executions with optional filters. Returns workflow runs with pass/fail counts.",
    inputSchema: {
      type: "object",
      properties: {
        limit: { type: "number", description: "Max results (1-100)", default: 20 },
        status: { type: "string", enum: ["success", "failure", "running"] },
        branch: { type: "string", description: "Filter by branch name" },
        suite: { type: "string", description: "Filter by test suite" },
        from: { type: "string", description: "Start date (ISO 8601)" },
        to: { type: "string", description: "End date (ISO 8601)" }
      }
    }
  },
  {
    name: "get_execution_details",
    description: "Get detailed info about a specific test execution including all test results and artifacts.",
    inputSchema: {
      type: "object",
      properties: {
        execution_id: { type: "number", description: "Execution ID" }
      },
      required: ["execution_id"]
    }
  },
  {
    name: "search_tests",
    description: "Search for tests by name or file path. Returns aggregated stats.",
    inputSchema: {
      type: "object",
      properties: {
        query: { type: "string", minLength: 2, description: "Search term" },
        limit: { type: "number", default: 20 }
      },
      required: ["query"]
    }
  },
  {
    name: "get_test_history",
    description: "Get execution history for a specific test across all runs.",
    inputSchema: {
      type: "object",
      properties: {
        test_signature: { type: "string", description: "Test signature (MD5 of file::name)" },
        test_name: { type: "string", description: "Alternative: search by test name" },
        limit: { type: "number", default: 20 }
      }
    }
  }
  // ... more tools defined in subsequent batches
]

/**
 * Handle tool calls with automatic org scoping
 */
export async function handleToolCall(
  name: string,
  args: Record<string, unknown>,
  authContext: AuthContext
) {
  const orgId = authContext.organizationId

  try {
    switch (name) {
      case "get_executions": {
        const input = z.object({
          limit: z.number().min(1).max(100).default(20),
          status: z.enum(["success", "failure", "running"]).optional(),
          branch: z.string().optional(),
          suite: z.string().optional(),
          from: z.string().optional(),
          to: z.string().optional()
        }).parse(args)

        const executions = await queries.getExecutions(
          orgId,
          input.limit,
          input.status,
          input.branch,
          input.suite,
          input.from,
          input.to
        )

        return {
          content: [{
            type: "text",
            text: JSON.stringify({
              organization: authContext.organizationSlug,
              count: executions.length,
              executions
            }, null, 2)
          }]
        }
      }

      case "get_execution_details": {
        const input = z.object({
          execution_id: z.number()
        }).parse(args)

        const execution = await queries.getExecutionById(orgId, input.execution_id)

        if (!execution) {
          return {
            content: [{
              type: "text",
              text: JSON.stringify({ error: "Execution not found or access denied" })
            }],
            isError: true
          }
        }

        const results = await queries.getTestResultsByExecutionId(orgId, input.execution_id)

        return {
          content: [{
            type: "text",
            text: JSON.stringify({
              execution,
              test_results: results,
              summary: {
                total: results.length,
                passed: results.filter(r => r.status === "passed").length,
                failed: results.filter(r => r.status === "failed").length
              }
            }, null, 2)
          }]
        }
      }

      case "search_tests": {
        const input = z.object({
          query: z.string().min(2),
          limit: z.number().min(1).max(100).default(20)
        }).parse(args)

        const tests = await queries.searchTests(orgId, input.query, input.limit)

        return {
          content: [{
            type: "text",
            text: JSON.stringify({
              query: input.query,
              count: tests.length,
              tests
            }, null, 2)
          }]
        }
      }

      // ... more tool handlers

      default:
        return {
          content: [{
            type: "text",
            text: JSON.stringify({ error: `Unknown tool: ${name}` })
          }],
          isError: true
        }
    }
  } catch (error) {
    return {
      content: [{
        type: "text",
        text: JSON.stringify({
          error: "Tool execution failed",
          message: error instanceof Error ? error.message : String(error)
        })
      }],
      isError: true
    }
  }
}
